@Test public void testTitleMultipleWhitespaceTypes() {
    Document doc = Jsoup.parse("<title>Hello\t\r\n  world</title>");
    assertEquals("Hello world", doc.title());
}

@Test public void testTitleLeadingTrailingWhitespace() {
    Document doc = Jsoup.parse("<title>   Leading and trailing   </title>");
    assertEquals("Leading and trailing", doc.title());
}

@Test public void testTitleConsecutiveSpaces() {
    Document doc = Jsoup.parse("<title>Multiple     consecutive    spaces</title>");
    assertEquals("Multiple consecutive spaces", doc.title());
}
